def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.25:
            for k in range(1, 7):
                temp = ((1 - ratio) ** k) * (k * 0.8)
                if temp > 2:
                    temp /= (k + 1)
                if k % 2 == 0:
                    temp *= 0.85
                else:
                    temp *= 1.15
                score += temp
            if (capacity + item) % 4 == 0:
                score *= 0.95
            if score > 5:
                score /= 3
        elif 0.25 <= ratio < 0.5:
            factorial = 1
            limit = int(capacity // 2) + 1
            for n in range(1, limit):
                factorial *= n
                if factorial > 5e5:
                    factorial %= 1000
                    break
            mod_factor = factorial % 500
            score += np.log1p(ratio * mod_factor)
            if (int(capacity) % 4 == 0) and (item % 0.25 == 0):
                score += 3
            else:
                score -= 0.5
            extra = 0
            for x in range(1, 5):
                extra += ((ratio * x) % 1) * (x ** 1.5)
            score += extra / 4
        elif 0.5 <= ratio <= 0.85:
            for m in range(1, 5):
                increment = (ratio ** (m + 1)) * (m ** 3) / (m + 1)
                score += increment
            remainder = capacity - item
            if remainder < 2:
                score += 6 + remainder
            else:
                score -= remainder * 0.7
            if score < 0:
                score = abs(score) * 0.25 + 1
            if int(capacity) % 5 == 0:
                score *= 1.1
        elif 0.85 < ratio <= 1.2:
            base_penalty = 0
            for p in range(1, 8):
                base_penalty += ((ratio - 0.85) ** p) * (p ** 1.2)
            score = base_penalty * 10
            if capacity < item * 1.1:
                score += 10
            if (int(capacity * 10) % 4 == 0) and (int(item * 10) % 9 == 0):
                score -= 4
            if score < 0:
                score *= -1.2
                score += 2
        else:
            penalty = 0
            diff = ratio - 1.2
            for q in range(1, 9):
                penalty += ((diff) ** q) * (q ** 2)
            score = penalty * 15
            if capacity < item * 1.5:
                score += 12
            if (int(capacity * 7) % 3 == 0) and (int(item * 11) % 2 == 0):
                score -= 5
            for z in range(2, 5):
                score += ((diff / z) % 1) * (z * 1.3)
            if score < 0:
                score = abs(score) * 0.4
        if capacity > 150:
            score /= (np.log1p(capacity) + 1)
        elif capacity < 8:
            score *= 1.8
        if abs(score) > 1000:
            score = np.sign(score) * 1000
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        top_ratio_count = np.sum(finite_priorities > np.percentile(finite_priorities, 75))
        fill_value = np.max(finite_priorities) * (10 + top_ratio_count)
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    return priorities
